
.call-phone {
	:deep(.modal-wrapper) {
		.modal-container {
			height: 60%;
		}

		.dialog__content {
			padding-bottom: calc(var(--default-grid-baseline) * 3);
		}
	}

	&__form {
		display: flex;
		align-items: flex-end;
		gap: var(--default-grid-baseline);
	}

	&__loading {
		margin: 0 !important;
		padding: 0 !important;
		height: 100%;
	}
}
