.file-preview{position:relative;min-width:0;max-width:100%;display:inline-block;border-radius:var(--border-radius);box-sizing:content-box !important}.file-preview:hover,.file-preview:focus,.file-preview:focus-visible{outline:none}.file-preview:hover .remove-file,.file-preview:focus .remove-file,.file-preview:focus-visible .remove-file{visibility:visible}.file-preview:hover .image-container:has(.file-preview__image.media),.file-preview:focus .image-container:has(.file-preview__image.media),.file-preview:focus-visible .image-container:has(.file-preview__image.media){outline:2px solid var(--color-primary-element)}.file-preview__image{object-fit:cover;transition:outline .1s ease-in-out}.file-preview__progress{position:absolute;top:50%;inset-inline-end:calc(var(--progress-bar-height)*-1);transform:translateY(-50%)}.file-preview .mimeicon{min-height:128px}.file-preview .mimeicon.preview-small{min-height:auto;max-height:24px}.file-preview .preview{border-radius:var(--border-radius);max-width:min(100%,600px);max-height:384px}.file-preview .preview-medium{border-radius:var(--border-radius);max-width:100%;max-height:192px}.file-preview .preview-small{border-radius:var(--border-radius);max-width:100%;max-height:24px}.file-preview .preview-loading{position:absolute;border-radius:var(--border-radius);width:100%;height:100%;background-color:var(--color-background-dark)}.file-preview .image-container{position:relative;display:inline-flex;width:100%;height:100%;max-width:100%;max-height:100%;border-radius:var(--border-radius)}.file-preview .image-container.playable .preview{transition:filter 250ms ease-in-out}.file-preview .image-container.playable .play-video-button{position:absolute;height:48px;top:50%;left:50%;transform:translate(-50%, -50%);opacity:.8;z-index:1;transition:opacity 250ms ease-in-out}.file-preview .image-container.playable:hover .preview{filter:brightness(80%)}.file-preview .image-container.playable:hover .play-video-button{opacity:1}.file-preview .name-container{font-weight:bold;width:100%;overflow:hidden;white-space:nowrap;text-overflow:ellipsis}.file-preview:not(.file-preview--viewer-available) strong:after{content:" ↗"}.file-preview--upload-editor{max-width:140px;max-height:140px;padding:12px 12px 24px 12px;margin:10px}.file-preview--upload-editor .preview{margin:auto;width:128px;height:128px}.file-preview--row-layout{display:flex;align-items:center;border-radius:var(--border-radius);padding:2px 4px}.file-preview--row-layout .image-container{flex-shrink:0;width:24px}.file-preview--row-layout .name-container{padding:0 4px;font-weight:normal}.file-preview--shared-items-grid{aspect-ratio:1;line-height:0}.file-preview--shared-items-grid .preview{width:100%;min-height:unset;height:100% !important}.remove-file{visibility:hidden;position:absolute !important;top:8px;inset-inline-end:8px}