
.conversation__subname {
	display: flex;
	gap: var(--default-grid-baseline);

	&-actor {
		flex: 0 1 auto;
		overflow: hidden;
		text-overflow: ellipsis;
		white-space: nowrap;
	}
	&-icon {
		flex-shrink: 0;
	}
	&-message {
		flex: 1 1 0;
		overflow: hidden;
		text-overflow: ellipsis;
		white-space: nowrap;
	}
}
