
.shared-items-browser {
	width: 100%;
	height: 100%;
	position: relative;
	display: flex;
	flex-direction: column;

	&__navigation {
		display: flex;
		gap: 8px;
		padding: 16px 16px 4px;
		flex-wrap: wrap;
		justify-content: center;
	}

	&__content {
		overflow-y: auto;
		overflow-x: hidden;
		padding: 12px;
	}
}

:deep(.modal-container) {
	height: 700px;
}

:deep(.button-vue) {
	border-radius: var(--border-radius-large);

	&.active {
		background-color: var(--color-primary-element-light);
	}
}
