

.ban-item {
	padding: 4px 0;
	&:not(:last-child) {
		border-bottom: 1px solid var(--color-border);
	}

	&__header {
		display: flex;
		justify-content: space-between;
		align-items: center;
	}

	&__caption {
		font-weight: bold;
	}

	&__hint {
		overflow-wrap: break-word;
		color: var(--color-text-maxcontrast);
		margin-bottom: 4px;
	}

	&__buttons {
		display: flex;
	}
}
