
section {
	grid-row: 1/3;
}

.avatar {
	&__container {
		display: flex;
		flex-flow: row wrap;
		justify-content: center;
		align-items: flex-start;
		gap: 16px;
	}

	&__controls {
		display: flex;
		flex-direction: column;
		align-items: center;
		gap: 16px;
	}

	&__warning {
		color: var(--color-text-maxcontrast);
	}

	&__preview {
		display: flex;
		justify-content: center;
		align-items: center;
		flex-shrink: 0;
		width: 300px;
		height: 180px;
		padding: 0 60px;

		&-emoji {
			display: flex;
			justify-content: center;
			align-items: center;
			width: 100%;
			height: 100%;
			padding-bottom: 6px;
			border-radius: 100%;
			background-color: var(--color-text-maxcontrast);
			font-size: 575%;
			line-height: 100%;

			&--dark {
				background-color: #3B3B3B;
			}
		}
	}

	&__buttons {
		display: flex;
		gap: 10px;
	}

	&__cropper {
		width: 300px;
		height: 300px;
		overflow: hidden;

		&:deep(.cropper-view-box) {
			border-radius: 50%;
		}
	}
}

input[type="file"] {
	display: none;
}

