.shared-items{display:grid;grid-template-columns:repeat(3, 1fr);gap:var(--default-grid-baseline);margin:auto}.shared-items__media{grid-template-columns:repeat(5, 1fr)}.shared-items__list{grid-template-columns:1fr}.shared-items__location{height:150px;margin-block:var(--default-grid-baseline)}.shared-items__other{padding-inline-start:calc(var(--default-grid-baseline)*2)}.shared-items__other a{text-decoration:underline}.shared-items__other a:after{content:" ↗"}